svg.script:
    (function () {
      var root = document.querySelector('svg > g[id], g[id]');
      if (!root) {
        return;
      }

      var legendItems = Array.prototype.slice.call(root.querySelectorAll('.legend-item'));
      var segments = Array.prototype.slice.call(root.querySelectorAll('.bars path[data-bar-key]'));
      var valueLabels = Array.prototype.slice.call(root.querySelectorAll('.bar-value-label[data-bar-key]'));

      if (legendItems.length === 0 || segments.length === 0 || valueLabels.length === 0) {
        return;
      }

      function legendSeries(item) {
        var swatch = item.querySelector('circle[class]');
        return swatch ? swatch.getAttribute('class') : null;
      }

      function setLabelTypography(label, size, weight) {
        label.style.fontSize = size;
        label.style.fontWeight = weight;
        Array.prototype.forEach.call(label.querySelectorAll('tspan'), function (span) {
          span.style.fontSize = size;
          span.style.fontWeight = weight;
        });
      }

      legendItems.forEach(function (item) {
        var series = legendSeries(item);
        if (!series) {
          return;
        }

        item.setAttribute('data-series', series);
        if (!item.hasAttribute('tabindex')) {
          item.setAttribute('tabindex', '0');
        }
        item.style.cursor = 'pointer';

        var container = item.querySelector('rect.legend-item-container');
        if (container) {
          container.style.transition = 'opacity 220ms ease-in-out, stroke 220ms ease-in-out, stroke-width 220ms ease-in-out';
        }

        var label = item.querySelector('text.legend-label');
        if (label) {
          label.style.transition = 'opacity 220ms ease-in-out';
        }
      });

      segments.forEach(function (segment) {
        segment.style.cursor = 'pointer';
        segment.style.transition = 'opacity 220ms ease-in-out, fill-opacity 220ms ease-in-out, stroke-opacity 220ms ease-in-out';
      });

      valueLabels.forEach(function (label) {
        if (!label.style.transition) {
          label.style.transition = 'opacity 220ms ease-in-out, font-size 220ms ease-in-out, fill-opacity 220ms ease-in-out';
        }
      });

      var activeMode = null;
      var activeSeries = null;
      var activeBarKey = null;
      var clearTimer = null;

      function cancelPendingClear() {
        if (clearTimer !== null) {
          window.clearTimeout(clearTimer);
          clearTimer = null;
        }
      }

      function scheduleClearActiveState() {
        cancelPendingClear();
        clearTimer = window.setTimeout(function () {
          activeMode = null;
          activeSeries = null;
          activeBarKey = null;
          renderState();
        }, 50);
      }

      function renderState() {
        legendItems.forEach(function (item) {
          var isSeriesActive = activeMode === 'series' && item.getAttribute('data-series') === activeSeries;
          var container = item.querySelector('rect.legend-item-container');

          item.style.opacity = activeMode === null ? '1' : (isSeriesActive ? '1' : '0.4');
          if (container) {
            container.style.stroke = isSeriesActive ? 'var(--color-text-dark)' : '';
            container.style.strokeWidth = isSeriesActive ? '1.5' : '';
          }
        });

        segments.forEach(function (segment) {
          var segmentSeries = segment.getAttribute('data-series');
          var segmentKey = segment.getAttribute('data-bar-key');
          var isSeriesActive = activeMode === 'series' && segmentSeries === activeSeries;
          var isSegmentActive = activeMode === 'segment' && segmentKey === activeBarKey;

          segment.style.opacity = (activeMode === null || isSeriesActive || isSegmentActive) ? '1' : '0.25';
        });

        valueLabels.forEach(function (label) {
          var isHoverOnly = label.classList.contains('hover-only');
          var labelSeries = label.getAttribute('data-series');
          var labelKey = label.getAttribute('data-bar-key');
          var isSeriesActive = activeMode === 'series' && labelSeries === activeSeries;
          var isLabelActive = activeMode === 'segment' && labelKey === activeBarKey;

          if (activeMode === null) {
            label.style.opacity = isHoverOnly ? '0' : '1';
            label.style.removeProperty('fill-opacity');
            setLabelTypography(label, '10px', '600');
          } else if (isSeriesActive || isLabelActive) {
            label.style.opacity = '1';
            label.style.fillOpacity = '1';
            setLabelTypography(label, '14px', '700');
          } else {
            label.style.opacity = isHoverOnly ? '0' : '0.25';
            label.style.removeProperty('fill-opacity');
            setLabelTypography(label, '10px', '600');
          }
        });
      }

      function activateSeries(series) {
        cancelPendingClear();
        activeMode = 'series';
        activeSeries = series;
        activeBarKey = null;
        renderState();
      }

      function activateSegment(barKey) {
        cancelPendingClear();
        activeMode = 'segment';
        activeSeries = null;
        activeBarKey = barKey;
        renderState();
      }

      function clearActiveState() {
        cancelPendingClear();
        activeMode = null;
        activeSeries = null;
        activeBarKey = null;
        renderState();
      }

      legendItems.forEach(function (item) {
        var series = item.getAttribute('data-series');
        if (!series) {
          return;
        }

        item.addEventListener('mouseenter', function () {
          activateSeries(series);
        });
        item.addEventListener('mouseleave', scheduleClearActiveState);
        item.addEventListener('focus', function () {
          activateSeries(series);
        });
        item.addEventListener('blur', clearActiveState);
      });

      segments.forEach(function (segment) {
        var barKey = segment.getAttribute('data-bar-key');
        if (!segment.hasAttribute('tabindex')) {
          segment.setAttribute('tabindex', '0');
        }

        segment.addEventListener('mouseenter', function () {
          activateSegment(barKey);
        });
        segment.addEventListener('mouseleave', scheduleClearActiveState);
        segment.addEventListener('focus', function () {
          activateSegment(barKey);
        });
        segment.addEventListener('blur', clearActiveState);
      });

      valueLabels.forEach(function (label) {
        var barKey = label.getAttribute('data-bar-key');
        if (!barKey) {
          return;
        }

        label.style.cursor = 'pointer';
        label.addEventListener('mouseenter', function () {
          activateSegment(barKey);
        });
        label.addEventListener('mouseleave', scheduleClearActiveState);
      });

      clearActiveState();
    }());
